+                        .create(true)
+                        .truncate(true)
+                        .write(true)
+                        .open(&seed_stdout_log)
+                    {
+                        let _ = file.write_all(&result.stdout);
+                    }
+                    if let Ok(mut file) = OpenOptions::new()
+                        .create(true)
+                        .truncate(true)
+                        .write(true)
+                        .open(&seed_stderr_log)
+                    {
+                        let _ = file.write_all(&result.stderr);
+                    }
+
+                    result.status.code().unwrap_or(1)
+                }
