+fn find_run_meta_files(suite_dir: &Path) -> Result<Vec<PathBuf>> {
+    let mut files = Vec::new();
+
+    for entry in fs::read_dir(suite_dir)? {
+        let entry = entry?;
+        if !entry.file_type()?.is_dir() {
+            continue;
+        }
+
+        let run_meta = entry.path().join("run_meta.json");
+        if run_meta.exists() {
+            files.push(run_meta);
+        }
+    }
+
+    files.sort();
