+}
+
+impl From<SeedDemoArgs> for SeedDemoConfig {
+    fn from(args: SeedDemoArgs) -> Self {
+        Self {
+            host: args.host,
+            port: args.port,
+            http_path: args.http_path,
+            auth_token: args.auth_token,
