+            profiles: Some("analytics-empty".to_string()),
+            binary: None,
+            app_command: None,
+            project_dir: None,
+            run_root: None,
+            suite_name: None,
+            host: None,
+            port: None,
+            http_path: None,
+            auth_token: None,
+            fail_fast: true,
+            skip_report: true,
+            keep_going: true,
+        };
+
+        assert!(args.keep_going);
+        assert!(args.fail_fast);
+    }
+}

