+            step_sleep: "1",
+            tail_sleep: "1",
+            keys: "#,sleep:2,q",
+        };
+
+        let tape = build_capture_tape(&spec);
+        assert!(tape.contains("Require \"/tmp/bin\""));
+        assert!(tape.contains("Set Theme \"GruvboxDark\""));
+        assert!(tape.contains("Type \"#\""));
